Insert into CLAIM_DECISION ("claim_id","decision","fusion_text","action","reasons_json","evidence_refs_json","confidence","est_payout_usd","created_at","created_by","updated_at","updated_by") values ('MOB-CLM-003','APPROVE_FAST_TRACK','This claim involves a collision at a stop-controlled intersection where the claimant''s vehicle was struck on the side by a red SUV entering from the right. The provided evidence includes clear images of damage to both vehicles and a video capturing the incident sequence, showing the red SUV proceeding into the intersection and making contact with the yellow car, followed by emergency responders arriving. The decision to approve on a fast-track basis is due to the policy being active, no prior claim existing, and the evidence, particularly the video, demonstrating high reliability that aligns with our approval rules for such modalities. This supports a straightforward payout without need for further review. Recommended next step is to process the payout promptly to the claimant.','PAYOUT','Policy active, no existing claim, high-confidence video evidence meets fast-track approval criteria per rules.','["/Volumes/claims_bronze/claims_db/evidence/counterparty_img_evidence/red_car.png", "/Volumes/claims_bronze/claims_db/evidence/claimant_img_evidence/yellow_car.png", "/Volumes/claims_bronze/claims_db/evidence/claimant_video_evidence/CarCollision.mp4"]',0.95,15000,to_timestamp('01-OCT-25 07.40.39.972700000 PM','DD-MON-RR HH.MI.SSXFF AM'),'system',to_timestamp('01-OCT-25 07.40.39.972700000 PM','DD-MON-RR HH.MI.SSXFF AM'),'system');
